    } catch (error) {
      console.error("Error in populateProducts:", error);
      res.status(500).send('An error occurred in populateProducts.');
    }
  });
});

// --- Clear Products Cloud Function ---
exports.clearProducts = functions.https.onRequest((req, res) => {
  cors(req, res, async () => {
    try {
      // await isAuthenticatedAdmin(context); // Temporarily commented out

      const productsRef = db.collection('products');
      // Query for documents where isTestData is true
      const snapshot = await productsRef.where('isTestData', '==', true).get();

      if (snapshot.empty) {
        res.status(200).json({ message: 'No test products found in "products" collection. Nothing to delete.' });
        return;
      }

      const batch = db.batch();
      snapshot.docs.forEach(doc => {
        batch.delete(doc.ref);
      });
      await batch.commit();
      res.status(200).json({ message: `Successfully deleted ${snapshot.docs.length} test documents from "products" collection.` });
    } catch (error) {
      console.error("Error in clearProducts:", error);
      res.status(500).send('An error occurred in clearProducts.');
    }
  });
});

// --- Clear Dishes Cloud Function ---
exports.clearDishes = functions.https.onRequest((req, res) => {
  cors(req, res, async () => {
    try {
      // await isAuthenticatedAdmin(context); // Temporarily commented out

      const dishesRef = db.collection('dishes');
      // Query for documents where isTestData is true
      const snapshot = await dishesRef.where('isTestData', '==', true).get();
      
      if (snapshot.empty) {
        res.status(200).json({ message: 'No test dishes found in "dishes" collection. Nothing to delete.' });
        return;
      }

      const batch = db.batch();
      snapshot.docs.forEach(doc => {
        batch.delete(doc.ref);
      });
      await batch.commit();
      res.status(200).json({ message: `Successfully deleted ${snapshot.docs.length} test documents from "dishes" collection.` });
    } catch (error) {
      console.error("Error in clearDishes:", error);
      res.status(500).send('An error occurred in clearDishes.');
    }
  });
});

// --- Populate Dishes Cloud Function ---
exports.populateDishes = functions.https.onRequest((req, res) => {
  cors(req, res, async () => {
    try {
      const productsSnapshot = await db.collection('products').get();
      const products = productsSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      const productNameToIdMap = {};
      products.forEach(p => {
        productNameToIdMap[p.name] = p.id;
      });

      const dishesRef = db.collection('dishes');
      const batch = db.batch();

      const testDishes = [
        { name: 'TEST - Lasagnes Bolognaises', category: 'Plat', price: 12.50, isAvailable: true, isTestData: true, ingredientNames: ['TEST - Pâtes Fraîches', 'TEST - Steak de Boeuf'] },
        { name: 'TEST - Tarte Tatin', category: 'Dessert', price: 6.00, isAvailable: true, isTestData: true, ingredientNames: ['TEST - Pommes Bio'] },
      ];

      testDishes.forEach(dish => {
        const ingredients = dish.ingredientNames
          .map(name => productNameToIdMap[name])
          .filter(id => id); // Filter out any ingredients not found

        if (ingredients.length > 0) {
          const { ingredientNames, ...dishData } = dish;
          batch.set(dishesRef.doc(), { ...dishData, ingredients });
        }
      });

      await batch.commit();
      res.status(200).json({ message: `Successfully added ${testDishes.length} test dishes.` });
    } catch (error) {
      console.error("Error in populateDishes:", error);
      res.status(500).send('An error occurred in populateDishes.');
    }
  });
});

// --- OCR Cloud Function for Expiry Date ---
exports.extractExpiryDateFromImage = functions.https.onCall(async (data, context) => {
  // Authentication / Authorization (optional, but recommended for callable functions)
  // if (!context.auth) {
  //   throw new functions.https.HttpsError('unauthenticated', 'The function must be called while authenticated.');
  // }

  const imageBuffer = Buffer.from(data.image, 'base64');

  try {
    const [result] = await visionClient.textDetection({
      image: { content: imageBuffer },
    });
    const detections = result.textAnnotations;
    const fullText = detections.length > 0 ? detections[0].description : '';

    console.log('Full text detected:', fullText);

    // Regex patterns for common date formats (DD/MM/YYYY, DD-MM-YYYY, YYYY-MM-DD, DD MM YYYY)
    const datePatterns = [
      /(\d{2})[./-](\d{2})[./-](\d{4})/, // DD/MM/YYYY or DD-MM-YYYY or DD.MM.YYYY
      /(\d{4})[./-](\d{2})[./-](\d{2})/, // YYYY-MM-DD
      /(\d{2})\s(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\s(\d{4})/i, // DD MMM YYYY
      /(\d{2})\s(\d{2})\s(\d{4})/ // DD MM YYYY (with spaces)
    ];

    let detectedDate = null;

    for (const pattern of datePatterns) {
      const match = fullText.match(pattern);
      if (match) {
        // Basic parsing based on pattern
        if (pattern === datePatterns[0] || pattern === datePatterns[3]) { // DD/MM/YYYY or DD MM YYYY
          const [ , day, month, year ] = match;
          detectedDate = `${year}-${month}-${day}`;
        } else if (pattern === datePatterns[1]) { // YYYY-MM-DD
          const [ , year, month, day ] = match;
          detectedDate = `${year}-${month}-${day}`;
        } else if (pattern === datePatterns[2]) { // DD MMM YYYY
          const [ , day, monthStr, year ] = match;
          const monthMap = {
            jan: '01', feb: '02', mar: '03', apr: '04', may: '05', jun: '06',
            jul: '07', aug: '08', sep: '09', oct: '10', nov: '11', dec: '12'
          };
          const month = monthMap[monthStr.toLowerCase()];
          detectedDate = `${year}-${month}-${day}`;
        }
        break; // Stop after first match
      }
    }

    if (detectedDate) {
      return { expiryDate: detectedDate, message: 'Date détectée.' };
    } else {
      return { expiryDate: null, message: 'Aucune date valide trouvée dans l\'image.' };
    }

  } catch (error) {
    console.error('Error during Vision API call or date extraction:', error);
    throw new functions.https.HttpsError('internal', 'Erreur lors du traitement de l\'image.', error.message);
  }
});

import { useState } from 'react';
import app, { db } from '../firebase/config'; // Import 'app'
import { collection, addDoc, Timestamp } from 'firebase/firestore';
// import { getFunctions, httpsCallable } from 'firebase/functions'; // Removed unused imports
import { getStorage, ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import Card from './Card';
import { PackagePlus } from 'lucide-react';
import ImageCapture from './ImageCapture'; // Import ImageCapture component

export default function ProductForm() {
  const [productName, setProductName] = useState('');
  const [weight, setWeight] = useState('');
  const [unit, setUnit] = useState('g');
  const [expiryDate, setExpiryDate] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [category, setCategory] = useState('');
  const [price, setPrice] = useState('');
  const [photo, setPhoto] = useState(null);
  const [capturedExpiryImage, setCapturedExpiryImage] = useState(null); // New state for captured image data

  const [isSaving, setIsSaving] = useState(false);
  const [feedback, setFeedback] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [ocrFeedback, setOcrFeedback] = useState('');

  // No longer need to initialize functions via getFunctions(app) here
  const storage = getStorage(app);

  const handleSaveProduct = async (e) => {
    e.preventDefault();
    setIsSaving(true);
    setFeedback('Sauvegarde...');

    if (!productName || !weight || !expiryDate || !quantity) {
      setFeedback('Veuillez remplir tous les champs obligatoires (Nom, Poids, Date de péremption, Quantité).');
      setIsSaving(false);
      return;
    }

    try {
      let photoURLs = [];
      if (photo) {
        const storageRef = ref(storage, `product_photos/${Date.now()}_${photo.name}`);
        const uploadResult = await uploadBytes(storageRef, photo);
        const downloadURL = await getDownloadURL(uploadResult.ref);
        photoURLs.push(downloadURL);
      }

      await addDoc(collection(db, 'products'), {
        name: productName,
        weight: parseFloat(weight),
        unit: unit,
        expiryDate: Timestamp.fromDate(new Date(expiryDate)),
        quantity: parseInt(quantity),
        category: category || null,
        price: price ? parseFloat(price) : null,
        photos: photoURLs,
        decisionStatus: 'to_handle', // Default status
        creationDate: Timestamp.now(),
      });
      setFeedback('Produit ajouté avec succès !');
      // Clear form
      setProductName('');
      setWeight('');
      setExpiryDate('');
      setQuantity(1);
      setCategory('');
      setPrice('');
      setPhoto(null);
      setCapturedExpiryImage(null); // Clear captured image
    } catch (error) {
      console.error("Error adding product:", error);
      setFeedback('Erreur lors de l\'ajout du produit.');
    } finally {
      setIsSaving(false);
      setTimeout(() => setFeedback(''), 3000);
    }
  };

  const handleScanProduct = async (imageData) => { // Accept imageData directly
    if (!imageData && !capturedExpiryImage) { // Check both if imageData is passed or if it's already in state
      setOcrFeedback('Veuillez capturer une photo de la date de péremption.');
      setTimeout(() => setOcrFeedback(''), 3000);
      return;
    }

    setIsScanning(true);
    setOcrFeedback('Scan en cours...');

    try {
      const base64Image = (imageData || capturedExpiryImage).split(',')[1]; // Use imageData if provided, else from state
      const expectedFunctionUrl = `https://us-central1-dashboard-mictlan-dev.cloudfunctions.net/extractExpiryDateFromImage`;

      const requestBody = {
          data: { // Re-wrapped data here
              image: base64Image
          }
      };

      const response = await fetch(expectedFunctionUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(requestBody),
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`HTTP error! status: ${response.status}, body: ${errorText}`);
      }

      const responseData = await response.json();

      if (responseData.data && responseData.data.expiryDate) {
        setExpiryDate(responseData.data.expiryDate);
        setOcrFeedback('Date détectée avec succès !');
      } else if (responseData.data) {
        setOcrFeedback(responseData.data.message);
      } else {
        setOcrFeedback(`Erreur inattendue: ${JSON.stringify(responseData)}`);
      }

    } catch (error) {
      console.error("Error during OCR scan:", error);
      setOcrFeedback(`Erreur lors du scan: ${error.message}`);
    } finally {
      setIsScanning(false);
      setTimeout(() => setOcrFeedback(''), 3000);
    }
  };

  return (
    <Card title="Ajouter un Produit" titleIcon={<PackagePlus />}>
      <form onSubmit={handleSaveProduct} className="space-y-4 text-xs">
        <div>
          <label htmlFor="productName" className="block text-gray-400 mb-1">Nom du Produit <span className="text-red-500">*</span></label>
          <input
            type="text"
            id="productName"
            value={productName}
            onChange={(e) => setProductName(e.target.value)}
            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            placeholder="Ex: Yaourt Grec Nature"
            required
          />
        </div>

        <div className="flex space-x-4">
          <div className="flex-1">
            <label htmlFor="weight" className="block text-gray-400 mb-1">Poids <span className="text-red-500">*</span></label>
            <input
              type="number"
              id="weight"
              value={weight}
              onChange={(e) => setWeight(e.target.value)}
              className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
              placeholder="Ex: 150"
              required
            />
          </div>
          <div className="flex-1">
            <label htmlFor="unit" className="block text-gray-400 mb-1">Unité</label>
            <select
              id="unit"
              value={unit}
              onChange={(e) => setUnit(e.target.value)}
              className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            >
              <option value="g">grammes (g)</option>
              <option value="ml">millilitres (ml)</option>
              <option value="unit">unité(s)</option>
            </select>
          </div>
        </div>

        <div>
          <label htmlFor="quantity" className="block text-gray-400 mb-1">Quantité <span className="text-red-500">*</span></label>
          <input
            type="number"
            id="quantity"
            value={quantity}
            onChange={(e) => setQuantity(e.target.value)}
            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            placeholder="Ex: 1"
            required
            min="1"
          />
        </div>

        <div>
          <label htmlFor="expiryDate" className="block text-gray-400 mb-1">Date de Péremption <span className="text-red-500">*</span></label>
          <input
            type="date"
            id="expiryDate"
            value={expiryDate}
            onChange={(e) => setExpiryDate(e.target.value)}
            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            required
          />
        </div>

        <div>
          <label htmlFor="category" className="block text-gray-400 mb-1">Catégorie (optionnel)</label>
          <input
            type="text"
            id="category"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            placeholder="Ex: Laitier, Viande, Légumes"
          />
        </div>

        <div>
          <label htmlFor="price" className="block text-gray-400 mb-1">Prix (optionnel)</label>
          <input
            type="number"
            id="price"
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            placeholder="Ex: 2.50"
            step="0.01"
          />
        </div>

        <div>
          <label htmlFor="photo" className="block text-gray-400 mb-1">Photo du Produit</label>
          <input
            type="file"
            id="photo"
            onChange={(e) => setPhoto(e.target.files[0])}
            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
            accept="image/*"
          />
          {photo && (
            <img src={URL.createObjectURL(photo)} alt="Prévisualisation du produit" className="mt-2 max-h-32 object-contain rounded" />
          )}
        </div>

        <ImageCapture onCapture={(imageData) => {
            setCapturedExpiryImage(imageData);
            handleScanProduct(imageData);
        }} />
        {ocrFeedback && <p className="mt-2 text-center text-sm text-blue-400">{ocrFeedback}</p>}
        <button
          type="submit"
          disabled={isSaving}
          className="w-full bg-mictlan-gold hover:bg-mictlan-gold/80 text-black font-bold py-2 px-4 rounded-lg text-xs uppercase tracking-widest flex items-center justify-center transition-all disabled:opacity-50"
        >
          {isSaving ? 'Ajout en cours...' : 'Ajouter le Produit'}
        </button>
        {feedback && <p className="mt-2 text-center text-sm text-mictlan-gold">{feedback}</p>}
      </form>
    </Card>
